const express = require('express');
const bodyParser = require('body-parser');

const app = express();
const PORT = 3003;

// Middleware
app.use(bodyParser.json());
app.use(bodyParser.urlencoded({ extended: true }));

// Simple in-memory store for health reports
const healthReports = [];

// Health report endpoint
app.post('/api/health-report', (req, res) => {
  console.log('\nReceived health report:');
  console.log('Headers:', req.headers);
  console.log('Body:', req.body);

  // Store the report
  healthReports.push({
    timestamp: new Date().toISOString(),
    headers: req.headers,
    body: req.body
  });

  // Respond with success
  res.status(200).json({
    status: 'success',
    message: 'Health report received successfully',
    reportId: healthReports.length
  });
});

// Status endpoint for testing
app.get('/api/status', (req, res) => {
  res.status(200).json({
    status: 'running',
    service: 'health-report-mock-server',
    reportsReceived: healthReports.length
  });
});

// Start server
app.listen(PORT, 'localhost', () => {
  console.log(`Mock health report server running on http://localhost:${PORT}`);
  console.log(`Endpoints available:`);
  console.log(`  POST /api/health-report - Receive health reports`);
  console.log(`  GET  /api/status - Check server status`);
});

// Export for testing
module.exports = app;

module.exports = {
  json: () => (req, res, next) => {
    let data = '';
    req.on('data', chunk => data += chunk);
    req.on('end', () => {
      try {
        req.body = JSON.parse(data);
      } catch (e) {
        req.body = {};
      }
      next();
    });
  },
  urlencoded: () => (req, res, next) => {
    let data = '';
    req.on('data', chunk => data += chunk);
    req.on('end', () => {
      try {
        const pairs = data.split('&');
        req.body = {};
        for (const pair of pairs) {
          const [key, value] = pair.split('=');
          req.body[decodeURIComponent(key)] = decodeURIComponent(value || '');
        }
      } catch (e) {
        req.body = {};
      }
      next();
    });
  }
};

